// ── EMF Scrape Sheet → Supabase Transform ─────────────────────────────────
// Reads rows by COLUMN INDEX (0-based) matching the actual Google Sheet
// column order. Dropped/unused columns are read but discarded.
//
// Sheet column map (25 columns — current daily scrape sheet):
//  0  post_url
//  1  post_id
//  2  post_timestamp
//  3  content_type
//  4  caption
//  5  verticals          (Assigned Vertical)
//  6  comments
//  7  likes
//  8  views
//  9  scrape_date
//  10 username
//  11 model_code         ← DROPPED, skip
//  12 model_stage_name   (Model Stage Name)
//  13 x_score            (X-score)
//  14 followers
//  15 employee           (Employee)
//  16 tracking_link      (Tracking Link)
//  17 acc_no             (Acc. No.)
//  18 trial              (trial?)
//  19 thumbnail          ← DROPPED, skip
//  20 is_shared_to_feed  (is_shared_to_feed?)
//  21 shortcode          ← not in DB, skip
//  22 user_id            (userId)
//  23 talent_manager     (Talent Manager)
//  24 team               (Team)

function parseDate(val) {
  if (!val) return null;
  if (val instanceof Date) {
    const y = val.getFullYear();
    const m = String(val.getMonth() + 1).padStart(2, '0');
    const d = String(val.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  }
  const s = String(val).trim().slice(0, 10);
  // ISO format
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  // DD/MM/YYYY or MM/DD/YYYY
  const parts = s.split('/');
  if (parts.length === 3) {
    const [a, b, yr] = [parseInt(parts[0]), parseInt(parts[1]), parts[2]];
    if (a > 12) return `${yr}-${String(b).padStart(2,'0')}-${String(a).padStart(2,'0')}`;
    if (b > 12) return `${yr}-${String(a).padStart(2,'0')}-${String(b).padStart(2,'0')}`;
    // Ambiguous: assume DD/MM/YYYY
    return `${yr}-${String(b).padStart(2,'0')}-${String(a).padStart(2,'0')}`;
  }
  return null;
}

function toFloat(val) {
  if (val === null || val === undefined || val === '') return null;
  const f = parseFloat(val);
  return isFinite(f) ? f : null;
}

function toInt(val) {
  const f = toFloat(val);
  return f !== null ? Math.round(f) : null;
}

const BATCH_SIZE = 100;
const rows = $input.all();
const batches = [];
let buffer = [];
let skipped = 0;

for (const item of rows) {
  // Google Sheets node returns rows as objects keyed by header name.
  // We need values by position — get the raw values array.
  const vals = Object.values(item.json);
  // Pad to 25 columns
  while (vals.length < 25) vals.push(null);

  const username   = vals[10] ? String(vals[10]).trim() : null;
  const scrapeDate = parseDate(vals[9]);

  // Skip rows missing required fields
  if (!username || !scrapeDate) {
    skipped++;
    continue;
  }

  const rawPostId = vals[1];
  let postId = rawPostId ? String(rawPostId).trim() : null;
  if (postId && ['none', ''].includes(postId.toLowerCase())) postId = null;

  const rowKey = postId
    ? `${postId}__${scrapeDate}`
    : `acct__${username}__${scrapeDate}`;

  const employee = vals[15] && String(vals[15]).trim() !== '-'
    ? String(vals[15]).trim()
    : null;

  buffer.push({
    row_key:           rowKey,
    post_url:          vals[0]  ? String(vals[0])  : null,
    post_id:           postId,
    post_timestamp:    parseDate(vals[2]),
    content_type:      vals[3]  ? String(vals[3])  : null,
    caption:           vals[4]  ? String(vals[4])  : null,
    verticals:         vals[5]  ? String(vals[5])  : null,
    comments:          toFloat(vals[6]),
    likes:             toFloat(vals[7]),
    views:             toFloat(vals[8]) ?? 0,
    scrape_date:       scrapeDate,
    username:          username,
    // col 11 model_code  — skipped (dropped from DB)
    model_stage_name:  vals[12] ? String(vals[12]) : null,
    x_score:           toFloat(vals[13]),
    followers:         toFloat(vals[14]),
    employee:          employee,
    tracking_link:     vals[16] ? String(vals[16]) : null,
    acc_no:            toInt(vals[17]),
    trial:             vals[18] ? String(vals[18]) : null,
    // col 19 thumbnail        — skipped (dropped from DB)
    is_shared_to_feed: vals[20] != null ? Boolean(vals[20]) : null,
    // col 21 shortcode        — skipped (not in DB)
    user_id:           toInt(vals[22]),
    talent_manager:    vals[23] ? String(vals[23]) : null,
    team:              vals[24] ? String(vals[24]) : null,
  });

  if (buffer.length >= BATCH_SIZE) {
    batches.push([...buffer]);
    buffer = [];
  }
}

if (buffer.length > 0) batches.push(buffer);

console.log(`Rows processed: ${rows.length}, skipped: ${skipped}, batches: ${batches.length}`);

// Output one item per batch so the loop node iterates over batches
return batches.map((batch, i) => ({ json: { batchIndex: i + 1, totalBatches: batches.length, rows: batch } }));
